// --- Periodic Cleanup of Expired Tokens and Sessions ---
setInterval(() => {
    const now = Date.now();

    for (const [hashedId, session] of sessions.entries()) {
        if (now > session.expiresAt) {
            sessions.delete(hashedId);
        }
    }

    for (const [selector, record] of rememberMeTokens.entries()) {
        if (now > record.expiresAt) {
            rememberMeTokens.delete(selector);
        }
    }

    for (const [username, record] of failedAttempts.entries()) {
        if (now - record.lastAttempt > LOCKOUT_DURATION_MS) {
            failedAttempts.delete(username);
        }
    }
}, 60 * 1000); // Run every minute

